function checkIfPangram(s) {
    let found = new Array(26).fill(false);
    for (let c of s) {
        if (c >= 'a' && c <= 'z') {
            let index = c.charCodeAt(0) - 'a'.charCodeAt(0);
            found[index] = true;
        }
    }
    return found.every(f => f);
